/* wms-master-commcode-sql-oracle.xml - insertInterfaceCommCode */
INSERT INTO TWORK_INTF_COMCD_HD_RCV (
	   CTKEY			/* 센터코드 */
	 , COMHDKEY			/* 공통코드헤더키 */
	 , COMHDNM			/* 공통코드헤더명 */
	 , DELYN			/* 삭제여부 */
	 , PRCSYN			/* 처리여부 */
	 , PRCSDATE			/* 처리일시 */
	 , RCVDATE			/* 수신일시 */
	 , INSERTDATE		/* 입력일시 */
	 , INSERTURKEY		/* 입력자 */
	 , UPDATEDATE		/* 수정일시 */
	 , UPDATEURKEY		/* 수정자 */
	 )
VALUES (
	   #{ctkey}
	 , #{comhdkey}
	 , #{comhdnm}
	 , #{delyn}
	 , 'N'
	 , NULL
	 , #{sysdate}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

/* wms-master-commcode-sql-oracle.xml - insertTworkMstCtcdHd */
INSERT INTO TWORK_MST_CTCD_HD (
	   CTKEY			/* 센터 코드 */
	 , CTCDHDKEY		/* 센터 기준 코드 공통 코드 */
	 , CTCDHDNM			/* 센터 기준 공통 코드 명 */
	 , DELYN			/* 삭제여부 */
	 , INSERTDATE		/* 입력 일시 */
	 , INSERTURKEY		/* 입력 사용자 ID */
	 , UPDATEDATE		/* 수정 일시 */
	 , UPDATEURKEY		/* 수정 사용자 ID */
	 )
VALUES (
	   #{ctkey}
	 , #{comhdkey}
	 , #{comhdnm}
	 , COALESCE(#{delyn}, 'N')
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

/* wms-master-commcode-sql-oracle.xml - insertInterfaceCommCodeDt */
INSERT INTO TWORK_INTF_COMCD_DT_RCV (
	   CTKEY			/* 센터코드 */
	 , COMHDKEY			/* 공통코드헤더키 */
	 , COMDTKEY			/* 공통코드상세코드 */
	 , COMDTNM			/* 공통코드상세명 */
	 , LAKEY			/* 언어코드 */
	 , DTKEYORD			/* 상세코드순서 */
	 , CMT				/* 비고 */
	 , DELYN			/* 삭제여부 */
	 , PRCSYN			/* 처리여부 */
	 , PRCSDATE			/* 처리일시 */
	 , RCVDATE			/* 수신일시 */
	 , INSERTDATE		/* 입력일시 */
	 , INSERTURKEY		/* 입력자 */
	 , UPDATEDATE		/* 수정일시 */
	 , UPDATEURKEY		/* 수정자 */
	 )
VALUES (
	   #{ctkey}
	 , #{comhdkey}
	 , #{comdtkey}
	 , #{comdtnm}
	 , #{lakey}
	 , #{dtkeyord}
	 , #{cmt}
	 , #{delyn}
	 , 'N'
	 , NULL
	 , #{sysdate}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

/* wms-master-commcode-sql-oracle.xml - insertTworkMstCtcdDt */
INSERT INTO TWORK_MST_CTCD_DT (
	   CTKEY			/* 센터 코드 */
	 , CTCDHDKEY		/* 센터 기준 코드 공통 코드 */
	 , CTCDDTKEY		/* 센터 기준 코드 상세 코드 */
	 , LAKEY			/* 국가별 언어 코드 */
	 , CTCDDTORD		/* 센터 기준 코드 상세 순서 */
	 , CTCDDTNM			/* 센터 기준 코드 상세 명 */
	 , CTCDDTVAL		/* 센터 기준 코드 상세 값 */
	 , CMT				/* 설명 */
	 , DELYN			/* 삭제여부 */
	 , INSERTDATE		/* 입력 일시 */
	 , INSERTURKEY		/* 입력 사용자 ID */
	 , UPDATEDATE		/* 수정 일시 */
	 , UPDATEURKEY		/* 수정 사용자 ID */
)
VALUES (
	   #{ctkey}
	 , #{comhdkey}
	 , #{comdtkey}
	 , #{lakey}
	 , #{dtkeyord}
	 , #{comdtnm}
	 , #{comdtkey}
	 , #{cmt}
	 , COALESCE(#{delyn}, 'N')
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
     )
